from typing import Union, Optional


class ASTNode:
    def __init__(self, node_type: str, **kwargs):
        self.type = node_type
        if node_type == "number":
            self.value: float = kwargs.get("value", 0.0)
        elif node_type == "binop":
            self.op: str = kwargs.get("op", "")
            self.left: Optional["ASTNode"] = kwargs.get("left")
            self.right: Optional["ASTNode"] = kwargs.get("right")
        elif node_type == "unary":
            self.op: str = kwargs.get("op", "")
            self.operand: Optional["ASTNode"] = kwargs.get("operand")

    def __repr__(self) -> str:
        if self.type == "number":
            return f"ASTNode('number', value={self.value})"
        elif self.type == "binop":
            return f"ASTNode('binop', op='{self.op}', left={self.left}, right={self.right})"
        elif self.type == "unary":
            return f"ASTNode('unary', op='{self.op}', operand={self.operand})"
        return f"ASTNode('{self.type}')"


def parse(expression: str) -> ASTNode:
    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Empty input")

    result, pos = parse_expression(tokens, 0)
    if pos < len(tokens):
        raise ValueError("Invalid expression")
    return result


def tokenize(expression: str) -> list[str]:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c.isdigit() or c == ".":
            start = i
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                i += 1
            tokens.append(expression[start:i])
        elif c in "+-*/()":
            tokens.append(c)
            i += 1
        else:
            raise ValueError(f"Invalid token: {c}")

    return tokens


def parse_expression(tokens: list[str], pos: int) -> tuple[ASTNode, int]:
    left, pos = parse_term(tokens, pos)

    while pos < len(tokens) and tokens[pos] in "+-":
        op = tokens[pos]
        pos += 1
        right, pos = parse_term(tokens, pos)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left, pos


def parse_term(tokens: list[str], pos: int) -> tuple[ASTNode, int]:
    left, pos = parse_factor(tokens, pos)

    while pos < len(tokens) and tokens[pos] in "*/":
        op = tokens[pos]
        pos += 1
        right, pos = parse_factor(tokens, pos)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left, pos


def parse_factor(tokens: list[str], pos: int) -> tuple[ASTNode, int]:
    if pos >= len(tokens):
        raise ValueError("Unexpected end of expression")

    token = tokens[pos]

    if token == "(":
        pos += 1
        node, pos = parse_expression(tokens, pos)
        if pos >= len(tokens) or tokens[pos] != ")":
            raise ValueError("Unmatched parentheses")
        pos += 1
        return node, pos
    elif token == "-":
        pos += 1
        operand, pos = parse_factor(tokens, pos)
        return ASTNode("unary", op="-", operand=operand), pos
    elif token == "+":
        pos += 1
        return parse_factor(tokens, pos)
    elif token.replace(".", "", 1).isdigit():
        value = float(token)
        pos += 1
        return ASTNode("number", value=value), pos
    else:
        raise ValueError(f"Unexpected token: {token}")


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Invalid binary operation")
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        if node.operand is None:
            raise ValueError("Invalid unary operation")
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        elif node.op == "+":
            return operand_val

    raise ValueError("Invalid AST node")
